export default function CheckoutScreen() {
  const router = useRouter();
  const { items, restaurantId, restaurantName, totalAmount, clearCart } = useCart();
  const { customer, user } = useAuth();
  const [loading, setLoading] = useState(false);

  const handlePlaceOrder = async () => {
    console.log('Auth state:', { user: !!user, customer: !!customer, customerData: customer });

    if (!customer || !user) {
      Alert.alert('Error', 'Please login to place order');
      return;
    }

    if (!restaurantId || !restaurantName) {
      Alert.alert('Error', 'Restaurant information missing');
      return;
    }

    setLoading(true);

    try {
      // 1. Create order in Firestore (pending payment)
      const orderResult = await createOrder({
        customerId: user.uid,
        customerName: customer.name,
        customerEmail: customer.email,
        customerPhone: customer.phone || '',
        restaurantId,
        restaurantName,
        items: items.map(item => ({
          id: item.id,
          name: item.name,
          price: item.price,
          quantity: item.quantity,
          isVeg: item.isVeg ?? true,
        })),
        totalAmount,
      });

      if (!orderResult.success || !orderResult.id) {
        throw new Error(orderResult.error || 'Failed to create order');
      }

      // 2. Open Razorpay payment (test mode - no order_id needed)
      const paymentResponse = await RazorpayService.openPayment({
        amount: RazorpayService.toPaisa(totalAmount),
        customerName: customer.name,
        customerEmail: customer.email,
        customerPhone: customer.phone || '9999999999',
        description: `Order at ${restaurantName}`,
      });

      // 3. Update order with payment info
      await updateOrderPayment(
        orderResult.id!,
        paymentResponse.razorpay_payment_id,
        paymentResponse.razorpay_order_id
      );

      // 4. Success!
      clearCart();

      Alert.alert(
        'Order Placed! 🎉',
        `Order #${orderResult.orderNumber}\n\nYour order has been placed successfully. You will be notified when it's ready.`,
        [{ text: 'Track Order', onPress: () => router.replace('/(tabs)/orders') }]
      );

    } catch (error: any) {
      if (error.message === 'Payment cancelled') {
        Alert.alert('Payment Cancelled', 'Your order was not placed.');
      } else {
        Alert.alert('Error', error.message || 'Failed to place order. Please try again.');
      }
    } finally {
      setLoading(false);
    }
  };

  if (items.length === 0) {
    router.back();
    return null;
  }

  return (
    <SafeAreaView style={styles.container} edges={['top', 'bottom']}>
      {/* Header */}
      <View style={styles.header}>
        <TouchableOpacity onPress={() => router.back()} style={styles.backButton}>
          <Ionicons name="arrow-back" size={24} color={colors.textPrimary} />
        </TouchableOpacity>
        <Text style={styles.headerTitle}>Checkout</Text>
        <View style={styles.backButton} />
      </View>

      <ScrollView showsVerticalScrollIndicator={false}>
        {/* Delivery Info */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <Ionicons name="person-outline" size={20} color={colors.textPrimary} />
            <Text style={styles.sectionTitle}>Your Details</Text>
          </View>
          <View style={styles.detailRow}>
            <Text style={styles.detailLabel}>Name</Text>
            <Text style={styles.detailValue}>{customer?.name}</Text>
          </View>
          <View style={styles.detailRow}>
            <Text style={styles.detailLabel}>Phone</Text>
            <Text style={styles.detailValue}>{customer?.phone || 'Not provided'}</Text>
          </View>
          {customer?.rollNumber && (
            <View style={styles.detailRow}>
              <Text style={styles.detailLabel}>Roll No.</Text>
              <Text style={styles.detailValue}>{customer.rollNumber}</Text>
            </View>
          )}
        </View>

        {/* Order Summary */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <Ionicons name="restaurant-outline" size={20} color={colors.textPrimary} />
            <Text style={styles.sectionTitle}>{restaurantName}</Text>
          </View>
          {items.map(item => (
            <View key={item.id} style={styles.orderItem}>
              <View style={[styles.vegIndicator, item.isVeg ? styles.vegVeg : styles.vegNonVeg]}>
                <View style={[styles.vegDot, item.isVeg ? styles.dotVeg : styles.dotNonVeg]} />
              </View>
              <Text style={styles.orderItemName} numberOfLines={1}>{item.name}</Text>
              <Text style={styles.orderItemQty}>x{item.quantity}</Text>
              <Text style={styles.orderItemPrice}>{formatPrice(item.price * item.quantity)}</Text>
            </View>
          ))}
        </View>

        {/* Payment Method */}
        <View style={styles.section}>
          <View style={styles.sectionHeader}>
            <Ionicons name="card-outline" size={20} color={colors.textPrimary} />
            <Text style={styles.sectionTitle}>Payment</Text>
          </View>
          <TouchableOpacity style={styles.paymentOption}>
            <View style={styles.paymentIcon}>
              <Ionicons name="phone-portrait" size={24} color={colors.primary} />
            </View>
            <View style={styles.paymentInfo}>
              <Text style={styles.paymentName}>UPI / Google Pay</Text>
              <Text style={styles.paymentDesc}>Pay using any UPI app</Text>
            </View>
            <View style={styles.radioSelected}>
              <View style={styles.radioDot} />
            </View>
          </TouchableOpacity>
        </View>

        {/* Bill */}
        <View style={styles.section}>
          <View style={styles.billRow}>
            <Text style={styles.billLabel}>Item Total</Text>
            <Text style={styles.billValue}>{formatPrice(totalAmount)}</Text>
          </View>
          <View style={styles.billRow}>
            <Text style={styles.billLabel}>Platform Fee</Text>
            <Text style={styles.billValue}>{formatPrice(0)}</Text>
          </View>
          <View style={[styles.billRow, styles.billTotal]}>
            <Text style={styles.totalLabel}>Total</Text>
            <Text style={styles.totalValue}>{formatPrice(totalAmount)}</Text>
          </View>
        </View>
      </ScrollView>

      {/* Place Order Button */}
      <View style={styles.footer}>
        <Button 
          title={loading ? 'Placing Order...' : `Pay ${formatPrice(totalAmount)}`}
          onPress={handlePlaceOrder}
          disabled={loading}
          fullWidth
        />
      </View>

      {loading && (
        <View style={styles.loadingOverlay}>
          <ActivityIndicator size="large" color={colors.primary} />
          <Text style={styles.loadingText}>Placing your order...</Text>
        </View>
      )}
    </SafeAreaView>
  );
}

