import { initializeApp, getApps } from 'firebase/app';
import { getAuth } from 'firebase/auth';
import { getFirestore } from 'firebase/firestore';
import { 
  collection, 
  doc, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  getDocs, 
  getDoc,
  query, 
  where, 
  orderBy 
} from 'firebase/firestore';

const firebaseConfig = {
  apiKey: process.env.EXPO_PUBLIC_FIREBASE_API_KEY,
  authDomain: process.env.EXPO_PUBLIC_FIREBASE_AUTH_DOMAIN,
  projectId: process.env.EXPO_PUBLIC_FIREBASE_PROJECT_ID,
  storageBucket: process.env.EXPO_PUBLIC_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: process.env.EXPO_PUBLIC_FIREBASE_MESSAGING_SENDER_ID,
  appId: process.env.EXPO_PUBLIC_FIREBASE_APP_ID
};

const app = getApps().length === 0 ? initializeApp(firebaseConfig) : getApps()[0];
const db = getFirestore(app, 'foood');

// Restaurant operations
export const createRestaurant = async (restaurantData) => {
  try {
    const docRef = await addDoc(collection(db, 'restaurants'), {
      ...restaurantData,
      createdAt: new Date(),
      updatedAt: new Date()
    });
    return { success: true, id: docRef.id };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

export const getRestaurant = async (restaurantId) => {
  try {
    const docRef = doc(db, 'restaurants', restaurantId);
    const docSnap = await getDoc(docRef);
    if (docSnap.exists()) {
      return { success: true, data: { id: docSnap.id, ...docSnap.data() } };
    } else {
      return { success: false, error: 'Restaurant not found' };
    }
  } catch (error) {
    return { success: false, error: error.message };
  }
};

// Menu item operations (now part of restaurant document)
export const createMenuItem = async (restaurantId, menuItemData) => {
  try {
    const restaurantRef = doc(db, 'restaurants', restaurantId);
    const restaurantDoc = await getDoc(restaurantRef);

    if (!restaurantDoc.exists()) {
      return { success: false, error: 'Restaurant not found' };
    }

    const currentMenu = restaurantDoc.data().menu || [];
    const newMenuItem = {
      id: Date.now().toString(), // Simple ID generation
      ...menuItemData,
      createdAt: new Date(),
      updatedAt: new Date()
    };

    const updatedMenu = [...currentMenu, newMenuItem];

    await updateDoc(restaurantRef, {
      menu: updatedMenu,
      updatedAt: new Date()
    });

    return { success: true, id: newMenuItem.id };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

export const getMenuItems = async (restaurantId) => {
  try {
    const restaurantRef = doc(db, 'restaurants', restaurantId);
    const restaurantDoc = await getDoc(restaurantRef);

    if (!restaurantDoc.exists()) {
      return { success: false, error: 'Restaurant not found' };
    }

    const menu = restaurantDoc.data().menu || [];
    // Sort by createdAt descending
    const sortedMenu = menu.sort((a, b) => {
      const aTime = a.createdAt?.seconds || 0;
      const bTime = b.createdAt?.seconds || 0;
      return bTime - aTime;
    });

    return { success: true, data: sortedMenu };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

export const updateMenuItemAvailability = async (restaurantId, itemId, isAvailable) => {
  try {
    const restaurantRef = doc(db, 'restaurants', restaurantId);
    const restaurantDoc = await getDoc(restaurantRef);

    if (!restaurantDoc.exists()) {
      return { success: false, error: 'Restaurant not found' };
    }

    const currentMenu = restaurantDoc.data().menu || [];
    const updatedMenu = currentMenu.map(item => 
      item.id === itemId 
        ? { ...item, isAvailable, updatedAt: new Date() }
        : item
    );

    await updateDoc(restaurantRef, {
      menu: updatedMenu,
      updatedAt: new Date()
    });

    return { success: true };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

export const updateMenuItem = async (restaurantId, itemId, updates) => {
  try {
    const restaurantRef = doc(db, 'restaurants', restaurantId);
    const restaurantDoc = await getDoc(restaurantRef);

    if (!restaurantDoc.exists()) {
      return { success: false, error: 'Restaurant not found' };
    }

    const currentMenu = restaurantDoc.data().menu || [];
    const updatedMenu = currentMenu.map(item => 
      item.id === itemId 
        ? { ...item, ...updates, updatedAt: new Date() }
        : item
    );

    await updateDoc(restaurantRef, {
      menu: updatedMenu,
      updatedAt: new Date()
    });

    return { success: true };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

export const deleteMenuItem = async (restaurantId, itemId) => {
  try {
    const restaurantRef = doc(db, 'restaurants', restaurantId);
    const restaurantDoc = await getDoc(restaurantRef);

    if (!restaurantDoc.exists()) {
      return { success: false, error: 'Restaurant not found' };
    }

    const currentMenu = restaurantDoc.data().menu || [];
    const updatedMenu = currentMenu.filter(item => item.id !== itemId);

    await updateDoc(restaurantRef, {
      menu: updatedMenu,
      updatedAt: new Date()
    });

    return { success: true };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

