// User operations
export const createUser = async (userData) => {
  try {
    const safeUserData = {
      userName: userData.userName || userData.name,
      userEmail: userData.userEmail || userData.email,
      userPhone: userData.userPhone || userData.phone,
      rollNumber: userData.rollNumber,
