    return { success: true, id: docRef.id };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

// Restaurant profile operations
export const getRestaurantProfile = async (restaurantId) => {
  try {
    const restaurantRef = doc(db, 'restaurants', restaurantId);
    const restaurantDoc = await getDoc(restaurantRef);

    if (!restaurantDoc.exists()) {
      return { success: false, error: 'Restaurant not found' };
    }

    return { success: true, data: { id: restaurantDoc.id, ...restaurantDoc.data() } };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

export const updateRestaurantProfile = async (restaurantId, updates) => {
  try {
    const restaurantRef = doc(db, 'restaurants', restaurantId);
    await updateDoc(restaurantRef, {
      ...updates,
      updatedAt: new Date()
    });
    return { success: true };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

export const updateOperatingHours = async (restaurantId, operatingHours) => {
  try {
    const restaurantRef = doc(db, 'restaurants', restaurantId);
    await updateDoc(restaurantRef, {
      operatingHours,
      updatedAt: new Date()
    });
    return { success: true };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

export const updateRestaurantGallery = async (restaurantId, gallery, heroImage = null) => {
  try {
    const restaurantRef = doc(db, 'restaurants', restaurantId);
    const updateData = {
      gallery,
      updatedAt: new Date()
    };

    if (heroImage) {
      updateData.heroImage = heroImage;
    }

    await updateDoc(restaurantRef, updateData);
    return { success: true };
  } catch (error) {
    return { success: false, error: error.message };
  }
};

