import { getOrders, updateOrderStatus, createOrder, createUser, getMenuItems } from '../../services/firestore';
import { textStyles } from '../../constants/typography';
import { colors, spacing, borderRadius, shadows } from '../../constants/theme';
import AnimatedButton from '../../components/ui/AnimatedButton';

export default function OrdersScreen() {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(false);

  const restaurantId = 'ealQV1vEMTTJ8LqE4jRW';

  useEffect(() => {
    loadOrders();
  }, []);

  const loadOrders = async () => {
    setLoading(true);
    const result = await getOrders(restaurantId);
    if (result.success) {
      setOrders(result.data);
    } else {
      Alert.alert('Error', result.error);
    }
    setLoading(false);
  };

  const simulateOrder = async () => {
    try {
      // Get available menu items
      const menuResult = await getMenuItems(restaurantId);
      if (!menuResult.success || menuResult.data.length === 0) {
        Alert.alert('Error', 'No menu items found');
        return;
      }

      const availableItems = menuResult.data.filter(item => item.isAvailable);
      if (availableItems.length === 0) {
        Alert.alert('Error', 'No available items to order');
        return;
      }

      const customerNames = ['Rahul Kumar', 'Priya Sharma', 'Amit Singh', 'Sneha Patel', 'Vikram Gupta', 'Ananya Das', 'Rohan Mehta', 'Kavya Reddy', 'Arjun Nair', 'Ishita Jain'];
      const customerName = customerNames[Math.floor(Math.random() * customerNames.length)];

      const customerData = {
        name: customerName,
        email: `${customerName.toLowerCase().replace(' ', '.')}@college.edu`,
        phone: `91987654${Math.floor(Math.random() * 10000).toString().padStart(4, '0')}`,
        rollNumber: `CS21B${Math.floor(Math.random() * 100).toString().padStart(3, '0')}`,
        hostel: ['Garnet', 'Sapphire', 'Ruby', 'Diamond', 'Emerald'][Math.floor(Math.random() * 5)] + ' Hostel',
        room: Math.floor(Math.random() * 300 + 100).toString()
      };

      const customerResult = await createUser(customerData);
      if (!customerResult.success) {
        Alert.alert('Error', 'Failed to create customer');
        return;
      }

      const orderNumber = 'ORD' + Date.now().toString().slice(-6);
      const numItems = Math.floor(Math.random() * 3) + 1;
      const orderItems = [];
      let subtotal = 0;

      for (let i = 0; i < numItems; i++) {
        const item = availableItems[Math.floor(Math.random() * availableItems.length)];
        const quantity = Math.floor(Math.random() * 2) + 1;
        const specialInstructions = Math.random() > 0.7 ? ['Extra spicy', 'Less oil', 'No onions', 'Extra sauce'][Math.floor(Math.random() * 4)] : '';

        orderItems.push({
          menuItemId: item.id,
          name: item.name,
          quantity,
          price: item.price,
          specialInstructions
        });
        subtotal += item.price * quantity;
      }

      const orderData = {
        orderNumber,
        restaurantId,
        customerId: customerResult.id,
        customerName: customerData.name,
        customerPhone: customerData.phone,
        items: orderItems,
        subtotal,
        tax: Math.round(subtotal * 0.05),
        total: Math.round(subtotal * 1.05),
        status: 'received',
        paymentStatus: 'paid',
        paymentMethod: ['UPI', 'Card', 'Cash'][Math.floor(Math.random() * 3)],
        estimatedTime: Math.floor(Math.random() * 20) + 10,
        notes: 'Order from mobile app'
      };

      const orderResult = await createOrder(orderData);
      if (orderResult.success) {
        loadOrders(); // Refresh orders immediately
        Alert.alert(
          '🎉 New Order Received!', 
          `Order #${orderNumber}\nCustomer: ${customerName}\nTotal: ₹${orderData.total}\nItems: ${orderItems.length}`,
          [{ text: 'OK', style: 'default' }]
        );
      } else {
        Alert.alert('Error', 'Failed to create order');
      }
    } catch (error) {
      Alert.alert('Error', 'Simulation failed: ' + error.message);
    }
  };

  const updateStatus = async (orderId, newStatus) => {
    const result = await updateOrderStatus(orderId, newStatus);
    if (result.success) {
      loadOrders();
    } else {
      Alert.alert('Error', result.error);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'received': return '#FF9800';
      case 'preparing': return '#2196F3';
      case 'ready': return '#4CAF50';
      case 'completed': return '#9E9E9E';
      default: return '#FF5722';
    }
  };

  const getNextStatus = (currentStatus) => {
    switch (currentStatus) {
      case 'received': return 'preparing';
      case 'preparing': return 'ready';
      case 'ready': return 'completed';
      default: return currentStatus;
    }
  };

  const getStatusEmoji = (status) => {
    switch (status) {
      case 'received': return '📝';
      case 'preparing': return '👨🍳';
      case 'ready': return '✅';
      case 'completed': return '🎉';
      default: return '❓';
    }
  };

  const renderOrder = ({ item }) => (
    <View style={styles.orderCard}>
      <View style={styles.orderHeader}>
        <View style={styles.orderNumberContainer}>
          <Text style={styles.orderNumber}>#{item.orderNumber}</Text>
          <Text style={styles.orderTime}>
            {new Date(item.createdAt.seconds * 1000).toLocaleTimeString()}
          </Text>
        </View>
        <View style={styles.paymentBadge}>
          <Text style={styles.paymentText}>{item.paymentMethod}</Text>
        </View>
      </View>

      <Text style={styles.customerName}>👤 {item.customerName}</Text>
      <Text style={styles.customerPhone}>📱 {item.customerPhone}</Text>

      <View style={styles.itemsList}>
        {item.items.map((orderItem, index) => (
          <View key={index} style={styles.orderItemRow}>
            <Text style={styles.orderItem}>
              {orderItem.quantity}x {orderItem.name}
            </Text>
            <Text style={styles.itemPrice}>₹{orderItem.price * orderItem.quantity}</Text>
          </View>
        ))}
      </View>

      <View style={styles.orderFooter}>
        <View style={styles.totalContainer}>
          <Text style={styles.totalAmount}>Total: ₹{item.total}</Text>
          <Text style={styles.estimatedTime}>⏱️ {item.estimatedTime} mins</Text>
        </View>
        <TouchableOpacity
          style={[styles.statusButton, { backgroundColor: getStatusColor(item.status) }]}
          onPress={() => updateStatus(item.id, getNextStatus(item.status))}
          disabled={item.status === 'completed'}
        >
          <Text style={styles.statusText}>
            {getStatusEmoji(item.status)} {item.status.toUpperCase()}
          </Text>
        </TouchableOpacity>
      </View>
    </View>
  );

  return (
    <View style={styles.container}>
      <TouchableOpacity style={styles.simulateButton} onPress={simulateOrder}>
        <Text style={[textStyles.button, styles.simulateButtonText]}>🧪 Simulate New Order</Text>
      </TouchableOpacity>

      {orders.length === 0 && !loading ? (
        <View style={styles.emptyState}>
          <Text style={styles.emptyText}>No orders yet</Text>
          <Text style={styles.emptySubtext}>Use the simulate button to create test orders</Text>
        </View>
      ) : (
        <FlatList
          data={orders}
          renderItem={renderOrder}
          keyExtractor={(item) => item.id}
          refreshing={loading}
          onRefresh={loadOrders}
          showsVerticalScrollIndicator={false}
          contentContainerStyle={styles.listContainer}
        />
      )}
    </View>
  );
}

