const handlePlaceOrder = async () => {
  console.log('Auth state:', { user: !!user, customer: !!customer, customerData: customer });

  if (!customer || !user) {
    Alert.alert('Error', 'Please login to place order');
    return;
  }

  if (!restaurantId || !restaurantName) {
    Alert.alert('Error', 'Restaurant information missing');
    return;
  }

  setLoading(true);
  let createdOrderId: string | null = null;
  let createdOrderNumber: string | null = null;

  try {
    // 1. Create order in Firestore (pending payment)
    const orderResult = await createOrder({
      customerId: user.uid,
      customerName: customer.name,
      customerEmail: customer.email,
      customerPhone: customer.phone || '',
      restaurantId,
      restaurantName,
      items: items.map(item => ({
        id: item.id,
        name: item.name,
        price: item.price,
        quantity: item.quantity,
        isVeg: item.isVeg ?? true,
      })),
      totalAmount,
    });

    if (!orderResult.success || !orderResult.id) {
      throw new Error(orderResult.error || 'Failed to create order');
    }

    createdOrderId = orderResult.id;
    createdOrderNumber = orderResult.orderNumber!;

    // 2. Open Razorpay payment
    const paymentResponse = await RazorpayService.openPayment({
      amount: RazorpayService.toPaisa(totalAmount),
      customerName: customer.name,
      customerEmail: customer.email,
      customerPhone: customer.phone || '9999999999',
      description: `Order #${createdOrderNumber} at ${restaurantName}`,
    });

    // 3. Payment SUCCESS - Update order
    await updateOrderPayment(
      createdOrderId,
      paymentResponse.razorpay_payment_id,
      paymentResponse.razorpay_order_id
    );

    // 4. Success!
    clearCart();

    Alert.alert(
      'Order Placed! 🎉',
      `Order #${createdOrderNumber}\n\nYour order has been placed successfully. You will be notified when it's ready.`,
      [{ text: 'Track Order', onPress: () => router.replace(`/order/${createdOrderId}`) }]
    );

  } catch (error: any) {
    // Payment FAILED or CANCELLED - Mark order as failed
    if (createdOrderId) {
      await markOrderPaymentFailed(createdOrderId, error.message);
    }

    if (error.message === 'Payment cancelled') {
      Alert.alert('Payment Cancelled', 'Your order was not placed. Please try again.');
    } else {
      Alert.alert('Payment Failed', error.message || 'Payment could not be completed. Please try again.');
    }
  } finally {
    setLoading(false);
  }
};

