import React, { createContext, useContext, useEffect, useState, ReactNode } from 'react';
import { onAuthStateChanged, signInWithEmailAndPassword, createUserWithEmailAndPassword, signOut, User } from 'firebase/auth';
import { auth } from '../services/firebase';
import { createCustomer, getCustomerByEmail } from '../services/firestore';

interface CustomerData {
  id: string;
  name: string;
  email: string;
  phone: string;
  rollNumber?: string;
  hostel?: string;
  room?: string;
}

interface AuthContextType {
  user: User | null;
  customer: CustomerData | null;
  loading: boolean;
  login: (email: string, password: string) => Promise<void>;
  signup: (email: string, password: string, customerData: Omit<CustomerData, 'id'>) => Promise<void>;
  logout: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [customer, setCustomer] = useState<CustomerData | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (user) => {
      setUser(user);
      if (user?.email) {
        const result = await getCustomerByEmail(user.email);
        if (result.success) {
          setCustomer(result.data as CustomerData);
        }
      } else {
        setCustomer(null);
      }
      setLoading(false);
    });
    return unsubscribe;
  }, []);

  const login = async (email: string, password: string) => {
    await signInWithEmailAndPassword(auth, email, password);
  };

  const signup = async (email: string, password: string, customerData: Omit<CustomerData, 'id'>) => {
    const userCredential = await createUserWithEmailAndPassword(auth, email, password);
    await createCustomer({ ...customerData, email });
  };

  const logout = async () => {
    await signOut(auth);
    setCustomer(null);
  };

  return (
    <AuthContext.Provider value={{ user, customer, loading, login, signup, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

