import { collection, addDoc, doc, updateDoc, getDoc, query, where, orderBy, getDocs, onSnapshot } from 'firebase/firestore';
import { db } from './firebase';

export interface OrderItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
  isVeg?: boolean;
}

export interface Order {
  id?: string;
  customerId: string;
  customerName: string;
  customerEmail: string;
  customerPhone: string;
  restaurantId: string;
  restaurantName: string;
  items: OrderItem[];
  totalAmount: number;
  status: 'pending' | 'confirmed' | 'preparing' | 'ready' | 'completed' | 'cancelled';
  paymentStatus: 'pending' | 'paid' | 'failed';
  paymentId?: string;
  razorpayOrderId?: string;
  orderNumber: string;
  createdAt: Date;
  updatedAt: Date;
}

// Generate a short order number
const generateOrderNumber = (): string => {
  const chars = 'ABCDEFGHJKLMNPQRSTUVWXYZ23456789';
  let result = '';
  for (let i = 0; i < 6; i++) {
    result += chars.charAt(Math.floor(Math.random() * chars.length));
  }
  return result;
};

export const createOrder = async (orderData: Omit<Order, 'id' | 'orderNumber' | 'createdAt' | 'updatedAt' | 'status' | 'paymentStatus'>) => {
  try {
    const order = {
      ...orderData,
      orderNumber: generateOrderNumber(),
      status: 'pending',
      paymentStatus: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    const docRef = await addDoc(collection(db, 'orders'), order);
    return { success: true, id: docRef.id, orderNumber: order.orderNumber };
  } catch (error: any) {
    return { success: false, error: error.message };

